function sanitiseForPrompt(rawText) {
  if (!rawText || typeof rawText !== 'string') return '';
  let clean = rawText.replace(/<[^>]*>/g, ' ');
  const patterns = [
    /ignore\s+(all\s+)?previous\s+instructions?/gi,
    /forget\s+(all\s+)?instructions?/gi,
    /you\s+are\s+now\s+/gi,
    /new\s+instructions?:/gi,
    /system\s*:/gi,
    /\[INST\]/gi, /\[\/INST\]/gi,
    /<\|im_start\|>/gi, /<\|im_end\|>/gi,
    /###\s*instruction/gi,
    /act\s+as\s+/gi,
    /pretend\s+(you\s+are|to\s+be)\s+/gi,
    /override\s+(the\s+)?system/gi,
    /jailbreak/gi,
  ];
  patterns.forEach(p => { clean = clean.replace(p, '[REDACTED]'); });
  clean = clean.substring(0, 2000);
  return clean.replace(/\s+/g, ' ').trim();
}
function decodeBase64Url(s) {
  if (!s) return '';
  return Buffer.from(s.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf8');
}
function findTextPart(p) {
  if (!p) return '';
  if (p.mimeType === 'text/plain' && p.body && p.body.data) return decodeBase64Url(p.body.data);
  if (p.parts && Array.isArray(p.parts)) {
    for (const x of p.parts) { const t = findTextPart(x); if (t) return t; }
  }
  if (p.mimeType === 'text/html' && p.body && p.body.data) return decodeBase64Url(p.body.data);
  return '';
}
function header(hs, name) {
  if (!hs) return null;
  const h = hs.find(x => x.name && x.name.toLowerCase() === name.toLowerCase());
  return h ? h.value : null;
}

const msg = $json;
const payload = msg.payload || {};
const headers = payload.headers || [];
const fromRaw = header(headers, 'From') || '';
const subject = header(headers, 'Subject') || '';
const dateHdr = header(headers, 'Date');
const internalDate = msg.internalDate ? new Date(parseInt(msg.internalDate, 10)).toISOString() : null;
const receivedAt = internalDate || (dateHdr ? new Date(dateHdr).toISOString() : new Date().toISOString());

let fromName = null;
let fromAddress = fromRaw;
const m = fromRaw.match(/^\s*"?([^"<]*?)"?\s*<([^>]+)>\s*$/);
if (m) { fromName = m[1].trim() || null; fromAddress = m[2].trim(); }

const bodyText = findTextPart(payload);
const bodyTextSafe = sanitiseForPrompt(bodyText);
const hasAttachment = !!(payload.parts && payload.parts.some(p => p.filename && p.filename.length > 0));

// A3_ATTACH_PARSE_v1
function walkAttachments(part, out) {
  if (!part) return;
  if (part.filename && part.filename.length > 0 && part.body && part.body.attachmentId) {
    out.push({
      filename: part.filename,
      mime_type: part.mimeType || 'application/octet-stream',
      attachment_id: part.body.attachmentId,
      size: part.body.size || 0
    });
  }
  if (Array.isArray(part.parts)) {
    for (const p of part.parts) walkAttachments(p, out);
  }
}
const attachments = [];
walkAttachments(payload, attachments);


return [{ json: {
  gmail_message_id: msg.id,
  account: 'personal1',  // A2_ACCOUNT_FIX_v1
  from_address: fromAddress,
  from_name: fromName,
  subject,
  body_text: bodyText,
  body_text_safe: bodyTextSafe,
  received_at: receivedAt,
  has_attachment: hasAttachment,
  attachments,
} }];

const hmacKey = $('Vault: Signing Key').item.json.data.data.payload_hmac_key;
const parsed = $json;

const eventPayload = {
  gmail_message_id: parsed.gmail_message_id,
  account: parsed.account,
  from_address: parsed.from_address,
  from_name: parsed.from_name,
  subject: parsed.subject,
  body_text: parsed.body_text,
  body_text_safe: parsed.body_text_safe,
  received_at: parsed.received_at,
  has_attachment: parsed.has_attachment,
};
const canonical = JSON.stringify(eventPayload, Object.keys(eventPayload).sort());
const crypto = require('crypto');
const signature = crypto.createHmac('sha256', hmacKey).update(canonical).digest('hex');

function S(v) {
  if (v === null || v === undefined) return 'NULL';
  if (typeof v === 'boolean' || typeof v === 'number') return String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}
function J(obj) {
  return "'" + JSON.stringify(obj).replace(/'/g, "''") + "'::jsonb";
}

// A1_DUP_FIX_v1
// Application-level idempotency: events.idempotency_key is non-unique
// because partitioned tables can't UNIQUE-index a non-partition-key
// column. WHERE NOT EXISTS ensures duplicate Gmail polls don't create
// new event rows for the same gmail_message_id.
const idemKey = 'email_' + parsed.gmail_message_id;
const sql = `
SET LOCAL app.current_entity = 'all';

INSERT INTO events (
  event_type, source, entity_id, payload, payload_signature,
  idempotency_key, pipeline_version
)
SELECT 'email.received', 'gmail', NULL, ${J(eventPayload)}, ${S(signature)},
       ${S(idemKey)}, ${S('gmail_ingest:1.0')}
 WHERE NOT EXISTS (
   SELECT 1 FROM events WHERE idempotency_key = ${S(idemKey)}
 )
RETURNING id, trace_id;
`;

// A3_ATTACH_SQL_v1
// Build one item for email.received + one item per attachment
// (document.received). The Postgres node downstream runs once per item.
const items = [{ json: { sql, gmail_message_id: parsed.gmail_message_id, kind: 'email_received' } }];

const attachments = parsed.attachments || [];
for (const att of attachments) {
  const docPayload = {
    gmail_message_id: parsed.gmail_message_id,
    attachment_id:    att.attachment_id,
    filename:         att.filename,
    mime_type:        att.mime_type,
    size:             att.size,
    account:          parsed.account,
    detected_at:      new Date().toISOString()
  };
  const docCanonical = JSON.stringify(docPayload, Object.keys(docPayload).sort());
  const docSig = crypto.createHmac('sha256', hmacKey).update(docCanonical).digest('hex');

  // Idempotency per SPEC §6.2 P9: report_{sha256(gmail_message_id+filename)}
  const idemRaw = parsed.gmail_message_id + ':' + att.filename;
  const idemHash = crypto.createHash('sha256').update(idemRaw).digest('hex');
  const docIdem = 'report_' + idemHash;

  const docSql = `
SET LOCAL app.current_entity = 'all';

INSERT INTO events (
  event_type, source, entity_id, payload, payload_signature,
  idempotency_key, pipeline_version
)
SELECT 'document.received', 'gmail', NULL, ${J(docPayload)}, ${S(docSig)},
       ${S(docIdem)}, ${S('gmail_ingest:1.0')}
 WHERE NOT EXISTS (
   SELECT 1 FROM events WHERE idempotency_key = ${S(docIdem)}
 )
RETURNING id, trace_id;
`;
  items.push({ json: { sql: docSql, gmail_message_id: parsed.gmail_message_id,
                       attachment_id: att.attachment_id, filename: att.filename,
                       kind: 'document_received' } });
}

return items;
